
import { defineComponent } from "vue";
import axios from "axios";

interface theySaidSoQuote {
  author: "string";
  quote: "string";
  tags: ["string"];
  id: "string";
  image: "string";
  length: 0;
}
interface theySaidSoResponseData {
  success: "string";
  contents: {
    quotes: theySaidSoQuote[];
  };
}
interface theySaidSoKey {
  key: string;
  type: "free" | "paid";
}

export default defineComponent({
  name: "QuoteBox",
  data: function () {
    return {
      quote: {} as theySaidSoQuote,
      apiKey: {} as theySaidSoKey,
    };
  },
  methods: {
    async getQuote(api: "qod" | "quote/random", params = {}) {
      this.quote = await axios
        .get(`https://quotes.rest/${api}`, {
          headers: { "X-TheySaidSo-Api-Secret": this.apiKey.key },
          params,
        })
        .then(function (response) {
          const content: theySaidSoResponseData = response.data;
          return content.contents.quotes[0];
        });
      console.log(this.quote);
    },
  },
});
